+            .prepare(
+                "SELECT 1 FROM approval_tokens
+                 WHERE workspace_id = ?1
+                   AND action_kind = ?2
+                   AND pane_id = ?3
+                   AND action_fingerprint = ?4
+                   AND used_at IS NULL
+                   AND expires_at >= ?5
+                 LIMIT 1",
+            )
+            .map_err(|e| {
+                StorageError::Database(format!("Failed to prepare approval scope query: {e}"))
+            })?;
+        stmt.query_row(
+            params![
+                workspace_id,
+                action_kind,
+                pane_id,
+                action_fingerprint,
+                now_ms
+            ],
+            |_| Ok(()),
+        )
+        .optional()
+        .map_err(|e| StorageError::Database(format!("Approval scope query failed: {e}")))?
+    } else {
+        let mut stmt = conn
+            .prepare(
+                "SELECT 1 FROM approval_tokens
+                 WHERE workspace_id = ?1
+                   AND action_kind = ?2
+                   AND pane_id IS NULL
+                   AND action_fingerprint = ?3
+                   AND used_at IS NULL
+                   AND expires_at >= ?4
+                 LIMIT 1",
+            )
+            .map_err(|e| {
+                StorageError::Database(format!("Failed to prepare approval scope query: {e}"))
+            })?;
