+            params![workspace_id, action_kind, action_fingerprint, now_ms],
+            |_| Ok(()),
+        )
+        .optional()
+        .map_err(|e| StorageError::Database(format!("Approval scope query failed: {e}")))?
+    };
+
+    Ok(found.is_some())
